        prefixA[i+1] = prefixA[i] + a
        let b = (1 - Int64(strategy[i])) * prices[i]
        prefixB[i+1] = prefixB[i] + b
    }

    let half = k / 2
    var maxDiff = 0

    for i in 0..<n - k + 1 {
        let sumA = prefixA[i + half] - prefixA[i]
        let sumB = prefixB[i + k] - prefixB[i + half]
        let currentDiff = sumA + sumB
        if currentDiff > maxDiff {
            maxDiff = currentDiff
        }
