func solve(prices: [Int64], strategy: [Int64], k: Int64) -> Int64 {
    let n = prices.count
    var original_sum = [Int64](repeating: 0, count: n + 1)
    for i in 1...n {
        original_sum[i] = original_sum[i-1] + strategy[i-1] * prices[i-1]
    }
    var price_prefix = [Int64](repeating: 0, count: n + 1)
    for i in 1...n {
        price_prefix[i] = price_prefix[i-1] + prices[i-1]
    }
    let original_total = original_sum[n]
    var max_gain = 0
    let half = k / 2
    for i in 0..<n - k + 1 {
        let end = i + k
        let start_second_half = i + half
        let sum_second_half = price_prefix[end] - price_prefix[start_second_half]
        let original_contribution = original_sum[end] - original_sum[i]
        let gain = sum_second_half - original_contribution
        if gain > max_gain {
            max_gain = gain
        }
    }
    return original_total + max_gain
}
